  1	import * as React from 'react';
  2	import { NamespaceStoreKind } from '@odf/core/types';
  3	import { getName } from '@odf/shared/selectors';
  4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  5	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
  6	import {
  7	  Flex,
  8	  FlexItem,
  9	  TextVariants,
 10	  Button,
 11	  ButtonVariant,
 12	  Form,
 13	  FormGroup,
 14	  TextInput,
 15	  Text,
 16	  Checkbox,
 17	  Split,
 18	  SplitItem,
 19	  Stack,
 20	  StackItem,
 21	} from '@patternfly/react-core';
 22	import { PlusCircleIcon, MinusCircleIcon } from '@patternfly/react-icons';
 23	import { NamespaceStoreDropdown } from '../namespace-store/namespace-store-dropdown';
 24	import { LogReplicationInfoForm } from './log-replication-info-form';
 25	import { LogReplicationInfo } from './state';
 26	
 27	type ReplicationFormProps = {
 28	  namespace: string;
 29	  updateParentState: (
 30	    rules: Rule[],
 31	    logReplicationInfo?: LogReplicationInfo
 32	  ) => void;
 33	  className?: string;
 34	  // For limiting the number of rules that can be added using add rule
 35	  ruleCountLimit?: number;
 36	};
 37	
 38	export type Rule = {
 39	  id: number;
 40	  namespaceStore: string;
 41	  prefix: string;
 42	  syncDeletion?: boolean;
 43	};
 44	
 45	const ModalComponent = React.lazy(
 46	  () => import('../namespace-store/namespace-store-modal')
 47	);
 48	
 49	export const ReplicationPolicyForm: React.FC<ReplicationFormProps> = ({
 50	  namespace,
 51	  updateParentState,
 52	  ruleCountLimit = 10,
 53	  className,
 54	}) => {
 55	  const [rules, setRules] = React.useState<Rule[]>([
 56	    { id: 1, namespaceStore: '', prefix: '' },
 57	  ]);
 58	
 59	  const [logReplicationInfo, setLogReplicationInfo] =
 60	    React.useState<LogReplicationInfo>({
 61	      logLocation: '',
 62	      logPrefix: '',
 63	    });
 64	
 65	  const { t } = useCustomTranslation();
 66	
 67	  const launchModal = useModal();
 68	
 69	  const [eventLogsEnabled, toggleEventLogs] = React.useState(false);
 70	
 71	  const handleNSChange = (ns: NamespaceStoreKind, ruleId: number) => {
 72	    const newRules = [...rules];
 73	    const index = newRules.findIndex((rule) => rule.id === ruleId);
 74	    newRules[index].namespaceStore = getName(ns);
 75	    setRules(newRules);
 76	    updateParentState(rules);
 77	  };
 78	
 79	  const handlePrefixChange = (value: string, ruleId: number) => {
 80	    const newRules = [...rules];
 81	    const index = newRules.findIndex((rule) => rule.id === ruleId);
 82	    newRules[index].prefix = value;
 83	    setRules(newRules);
 84	    updateParentState(rules);
 85	  };
 86	
 87	  const handleSyncDeletion = (value: boolean, ruleId: number) => {
 88	    const newRules = [...rules];
 89	    const index = newRules.findIndex((rule) => rule.id === ruleId);
 90	    newRules[index].syncDeletion = eventLogsEnabled ? value : false;
 91	    setRules(newRules);
 92	    let temp = { ...logReplicationInfo };
 93	    if (!newRules.some((rule) => rule.syncDeletion)) {
 94	      temp = { logLocation: null, logPrefix: null };
 95	      setLogReplicationInfo(temp);
 96	    }
 97	    updateParentState(rules, temp);
 98	  };
 99	
100	  const handleAddRule = () => {
101	    setRules([
102	      ...rules,
103	      { id: rules.length + 1, namespaceStore: '', prefix: '' },
104	    ]);
105	  };
106	
107	  const handleLogPrefixChange = (prefix: string) => {
108	    const repInfo = { ...logReplicationInfo, logPrefix: prefix };
109	    setLogReplicationInfo(repInfo);
110	    updateParentState(rules, repInfo);
111	  };
112	
113	  const handleLogLocationChange = (logLocation: string) => {
114	    const repInfo = { ...logReplicationInfo, logLocation: logLocation };
115	    setLogReplicationInfo(repInfo);
116	    updateParentState(rules, repInfo);
117	  };
118	  const handleRemoveRule = () => {
119	    let newRules = [...rules];
120	
121	    // will remove the last rule from the array
122	    newRules.splice(-1, 1);
123	    setRules(newRules);
124	    updateParentState(rules);
125	  };
126	
127	  const disableSyncDeletions = React.useCallback(
128	    (isEventLogEnabled: boolean) => {
129	      const newRules: Array<Rule> = rules.map((rule) => ({
130	        ...rule,
131	        syncDeletion: isEventLogEnabled ? rule.syncDeletion : false,
132	      }));
133	      setRules(newRules);
134	      updateParentState(newRules);
135	    },
136	    [rules, updateParentState]
137	  );
138	
139	  const onChangeEventLogs = (isEventLogEnabled: boolean) => {
140	    toggleEventLogs(isEventLogEnabled);
141	    disableSyncDeletions(isEventLogEnabled);
142	  };
143	
144	  const onClick = () =>
145	    launchModal(ModalComponent, { isOpen: true, namespace });
146	
147	  return (
148	    <div className={className}>
149	      <Form>
150	        <FormGroup>
151	          <Checkbox
152	            id="enable-event-logs"
153	            label={t('Optimize replication using event logs')}
154	            isChecked={eventLogsEnabled}
155	            description={t(
156	              'You must enable and configure object logging in the cloud environment of your choice'
157	            )}
158	            onChange={(_event, isEventLogEnabled: boolean) =>
159	              onChangeEventLogs(isEventLogEnabled)
160	            }
161	          />
162	        </FormGroup>
163	        <FormGroup>
164	          {eventLogsEnabled && (
165	            <LogReplicationInfoForm
166	              location={logReplicationInfo.logLocation}
167	              prefix={logReplicationInfo.logPrefix}
168	              onLogLocationChange={handleLogLocationChange}
169	              onPrefixChange={handleLogPrefixChange}
170	            />
171	          )}
172	        </FormGroup>
173	
174	        <Flex
175	          justifyContent={{ default: 'justifyContentSpaceBetween' }}
176	          alignItems={{ default: 'alignItemsCenter' }}
177	        >
178	          <FlexItem>
179	            <Text component={TextVariants.h3}>{t('Replication rules ')}</Text>
180	          </FlexItem>
181	          <FlexItem>
182	            <Button
183	              variant={ButtonVariant.link}
184	              className="nb-bc-step-page-form__modal-launcher"
185	              onClick={onClick}
186	            >
187	              <PlusCircleIcon /> {t('Create new NamespaceStore')}
188	            </Button>
189	          </FlexItem>
190	        </Flex>
191	        <Stack hasGutter className="odf-mcg__form">
192	          {rules.map((rule, index) => (
193	            <StackItem key={rule.id}>
194	              <Split hasGutter>
195	                <SplitItem className="odf-mcg__rule">
196	                  <RuleForm
197	                    index={index}
198	                    namespace={namespace}
199	                    rule={rule}
200	                    onNSChange={(ns: NamespaceStoreKind) =>
201	                      handleNSChange(ns, rule.id)
202	                    }
203	                    onPrefixChange={(val: string) =>
204	                      handlePrefixChange(val, rule.id)
205	                    }
206	                    onSyncDeletions={(val: boolean) =>
207	                      handleSyncDeletion(val, rule.id)
208	                    }
209	                    isSyncDeletionDisabled={!eventLogsEnabled}
210	                  />
211	                </SplitItem>
212	
213	                <SplitItem>
214	                  {rules.length === index + 1 && (
215	                    <Button
216	                      variant="link"
217	                      icon={<MinusCircleIcon />}
218	                      onClick={handleRemoveRule}
219	                      data-testid="remove-rule-btn"
220	                      data-test="remove-rule-btn"
221	                      className="odf-mcg__remove-button"
222	                    />
223	                  )}
224	                </SplitItem>
225	              </Split>
226	            </StackItem>
227	          ))}
228	          {rules.length < ruleCountLimit && (
229	            <StackItem>
230	              <Button
231	                id="add-rule-btn"
232	                variant="link"
233	                icon={<PlusCircleIcon />}
234	                onClick={handleAddRule}
235	                isInline
236	                data-testid="add-rule-btn"
237	                data-test="add-rule-btn"
238	              >
239	                {t('Add rule')}
240	              </Button>
241	            </StackItem>
242	          )}
243	        </Stack>
244	      </Form>
245	    </div>
246	  );
247	};
248	
249	type RuleFormProps = {
250	  namespace: string;
251	  rule: Rule;
252	  onNSChange: (ns: NamespaceStoreKind) => void;
253	  onPrefixChange: (val: string) => void;
254	  onSyncDeletions: (val: boolean) => void;
255	  isSyncDeletionDisabled: boolean;
256	  index?: number;
257	};
258	
259	export const RuleForm: React.FC<RuleFormProps> = ({
260	  namespace,
261	  rule,
262	  onNSChange,
263	  onPrefixChange,
264	  onSyncDeletions,
265	  isSyncDeletionDisabled,
266	  index,
267	}) => {
268	  const { t } = useCustomTranslation();
269	  return (
270	    <Stack className="odf-mcg__stack-item">
271	      <StackItem>
272	        <Split hasGutter>
273	          <SplitItem isFilled>
274	            <FormGroup
275	              fieldId="namespace-store-dropdown-field"
276	              label={t('NamespaceStore')}
277	              className="odf-mcg__namespacestore-dropdown"
278	              isRequired
279	            >
280	              <NamespaceStoreDropdown
281	                onChange={onNSChange}
282	                id="ns-dropdown"
283	                selectedKey={rule.namespaceStore}
284	                creatorDisabled={true}
285	                namespace={namespace}
286	              />
287	            </FormGroup>
288	          </SplitItem>
289	          <SplitItem isFilled>
290	            <FormGroup fieldId="prefix-input-field" label={t('Prefix')}>
291	              <TextInput
292	                data-test="prefix-input"
293	                placeholder={t('Enter a prefix')}
294	                type="text"
295	                id="prefix-input"
296	                value={rule.prefix}
297	                onChange={(_event, value) => onPrefixChange(value)}
298	                aria-label={t('Prefix')}
299	              />
300	            </FormGroup>
301	          </SplitItem>
302	        </Split>
303	      </StackItem>
304	      <StackItem>
305	        <FormGroup fieldId="sync-deletions-checkbox">
306	          <Checkbox
307	            data-test="sync-deletion"
308	            id="sync-deletions-checkbox"
309	            isChecked={rule.syncDeletion}
310	            isDisabled={isSyncDeletionDisabled}
311	            onChange={(_event, value) => onSyncDeletions(value)}
312	            description={
313	              index === 0
314	                ? t(
315	                    'Sync deletion syncs the delete operation. If you delete data from bucket 1, the same data gets deleted from bucket 2'
316	                  )
317	                : ''
318	            }
319	            aria-label={t('sync deletion')}
320	            label={t('Sync deletion')}
321	          />
322	        </FormGroup>
323	      </StackItem>
324	    </Stack>
325	  );
326	};

